+form {
+  display: grid;
+  gap: 14px;
+  padding: 16px;
   border: 1px solid var(--border);
+  border-radius: 14px;
+  background: var(--panel);
+}
+
+details.advanced {
+  border: 1px solid var(--border);
+  border-radius: 14px;
   background: var(--surface);
+  padding: 10px 12px;
 }

-.docsLink:hover {
-  border-color: color-mix(in srgb, var(--ui-focus) 55%, var(--border));
-  color: var(--text);
+details.advanced > summary {
+  cursor: pointer;
+  user-select: none;
+  list-style: none;
+  color: var(--muted);
+  font-size: 12px;
+  font-weight: 900;
+  letter-spacing: 0.3px;
 }

-form {
+details.advanced > summary::-webkit-details-marker {
+  display: none;
+}
+
+details.advanced > summary::after {
+  content: "▸";
+  float: right;
+  color: color-mix(in srgb, var(--muted) 85%, transparent);
+  transform: translateY(1px);
+}
+
+details.advanced[open] > summary::after {
+  content: "▾";
+}
+
+.advancedGrid {
   display: grid;
   gap: 14px;
-  padding: 16px;
-  border: 1px solid var(--border);
-  border-radius: 14px;
-  background: var(--panel);
+  margin-top: 12px;
+}
+
+#pickersRoot {
+  display: contents;
 }

